/**
 * logo.js — PerformanceIQ Phase 15C
 * Real logo: green glow ring + steel teal spiral disc
 * Colors: Volt Green #6FD94F · Teal Navy #002030 · Mid Teal #5090A0
 */

const ICON_96  = "data:image/png;base64,";
const ICON_48  = "data:image/png;base64,";
const ICON_140 = "data:image/png;base64,";
const WIDE     = "data:image/png;base64,";

/** Icon-only disc (square crop of spiral ring) */
export function mark(size = 96) {
  const src = size <= 48 ? ICON_48 : size <= 96 ? ICON_96 : ICON_140;
  return `<img src="${src}" width="${size}" height="${size}"
    alt="PerformanceIQ" class="piq-logo-mark"
    style="display:block;object-fit:contain;" />`;
}

/** Stacked lockup: icon + wordmark */
export function lockup(iconSize = 96) {
  const src = iconSize <= 48 ? ICON_48 : iconSize <= 96 ? ICON_96 : ICON_140;
  const fs  = Math.round(iconSize * 0.35);
  const fs2 = Math.round(iconSize * 0.35);
  return `
    <div class="piq-lockup piq-lockup--stacked" aria-label="PerformanceIQ">
      <div class="piq-logo-glow">
        <img src="${src}" width="${iconSize}" height="${iconSize}"
             alt="" aria-hidden="true"
             style="display:block;object-fit:contain;" />
      </div>
      <div style="text-align:center;line-height:1.1;margin-top:4px;">
        <div style="font-family:var(--font-display);font-size:${fs}px;
                    font-weight:700;color:var(--piq-text);letter-spacing:0.05em;">
          PERFORMANCE
        </div>
        <div style="font-family:var(--font-display);font-size:${fs2}px;
                    font-weight:700;color:var(--piq-green);letter-spacing:0.14em;">
          IQ
        </div>
      </div>
    </div>`;
}

/** Inline header version: disc icon left + wordmark right */
export function inline(iconSize = 32) {
  const src = iconSize <= 48 ? ICON_48 : ICON_96;
  const fs  = Math.round(iconSize * 0.44);
  return `
    <div class="piq-lockup piq-lockup--inline" aria-label="PerformanceIQ"
         style="display:inline-flex;align-items:center;gap:${Math.round(iconSize*0.28)}px;">
      <img src="${src}" width="${iconSize}" height="${iconSize}"
           alt="" aria-hidden="true"
           style="display:block;object-fit:contain;flex-shrink:0;" />
      <div style="line-height:1.05;">
        <span style="font-family:var(--font-display);font-size:${fs}px;
                     font-weight:700;color:var(--piq-text);letter-spacing:0.04em;">
          PERFORMANCE
        </span>
        <span style="font-family:var(--font-display);font-size:${fs}px;
                     font-weight:700;color:var(--piq-green);letter-spacing:0.1em;
                     margin-left:3px;">
          IQ
        </span>
      </div>
    </div>`;
}

/** Wide horizontal logo (full image with motion streaks) for splash screens */
export function wide(maxWidth = 260) {
  return `<img src="${WIDE}" style="max-width:${maxWidth}px;width:100%;
    display:block;object-fit:contain;margin:0 auto;"
    alt="PerformanceIQ" />`;
}
